queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?element_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:element_id ?cg . ?child a :Elements ; p:id ?cg . ?l p:urban_planner_id ?pg . ?parent a :Urban_Planners ; p:id ?pg . } GROUP BY ?child }
  ?child p:element_name ?element_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Urban_Planners } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?element_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:element_id ?cg . ?child a :Elements ; p:id ?cg . ?l p:urban_planner_id ?pg . ?parent a :Urban_Planners ; p:id ?pg . } GROUP BY ?child }
  ?child p:element_name ?element_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Urban_Planners } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?element_name WHERE {
  ?urban_planners_elements a :Urban_Planners_Elements .
  ?elements a :Elements .
  ?urban_planners_elements p:hasElements ?elements .
  ?urban_planners a :Urban_Planners .
  ?urban_planners_elements p:hasUrban_Planners ?urban_planners .
  ?urban_planners p:name ?name .
  ?elements p:element_name ?element_name .
} }
}
